import os
import uuid
import threading
import time
import hashlib
from concurrent.futures import ThreadPoolExecutor
from flask import Flask, request, jsonify, send_file, Response
from werkzeug.utils import secure_filename
from functools import wraps
from collections import defaultdict
import ffmpeg
import redis
import boto3
from botocore.exceptions import NoCredentialsError
from config import (  # Assume config.py contains sensitive info
    AWS_ACCESS_KEY,
    AWS_SECRET_KEY,
    S3_BUCKET_NAME,
    REDIS_HOST,
    REDIS_PORT,
    SECRET_KEY,
    UPLOAD_FOLDER,
    ALLOWED_EXTENSIONS
)

app = Flask(__name__)
app.secret_key = SECRET_KEY
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

# Initialize Redis for caching and rate limiting
redis_client = redis.StrictRedis(host=REDIS_HOST, port=REDIS_PORT, db=0)

# Initialize S3 client
s3_client = boto3.client(
    's3',
    aws_access_key_id=AWS_ACCESS_KEY,
    aws_secret_access_key=AWS_SECRET_KEY
)

# Thread pool for concurrent operations
executor = ThreadPoolExecutor(max_workers=10)

# In-memory structures (would be replaced with DB in production)
users = {}
videos = {}
video_metadata = defaultdict(dict)
user_sessions = {}

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        session_id = request.headers.get('Authorization')
        if not session_id or session_id not in user_sessions:
            return jsonify({"error": "Unauthorized"}), 401
        return f(*args, **kwargs)
    return decorated_function

def rate_limit(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        ip = request.remote_addr
        key = f"rate_limit:{ip}"
        current = redis_client.incr(key)
        if current == 1:
            redis_client.expire(key, 60)
        if current > 100:  # 100 requests per minute
            return jsonify({"error": "Rate limit exceeded"}), 429
        return f(*args, **kwargs)
    return decorated_function

@app.route('/register', methods=['POST'])
def register():
    data = request.json
    username = data.get('username')
    password = data.get('password')

    if not username or not password:
        return jsonify({"error": "Username and password required"}), 400

    if username in users:
        return jsonify({"error": "Username already exists"}), 400

    salt = os.urandom(32)
    key = hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, 100000)
    users[username] = {
        'salt': salt,
        'key': key
    }
    return jsonify({"message": "User created successfully"}), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    username = data.get('username')
    password = data.get('password')

    if not username or not password:
        return jsonify({"error": "Username and password required"}), 400

    user = users.get(username)
    if not user:
        return jsonify({"error": "Invalid credentials"}), 401

    new_key = hashlib.pbkdf2_hmac(
        'sha256',
        password.encode('utf-8'),
        user['salt'],
        100000
    )

    if new_key != user['key']:
        return jsonify({"error": "Invalid credentials"}), 401

    session_id = str(uuid.uuid4())
    user_sessions[session_id] = username
    return jsonify({"session_id": session_id}), 200

@app.route('/upload', methods=['POST'])
@login_required
@rate_limit
def upload_file():
    if 'file' not in request.files:
        return jsonify({"error": "No file part"}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({"error": "No selected file"}), 400

    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        unique_id = str(uuid.uuid4())
        temp_path = os.path.join(app.config['UPLOAD_FOLDER'], unique_id)
        file.save(temp_path)

        # Process video in background
        executor.submit(process_video, temp_path, unique_id, filename)

        return jsonify({
            "message": "File is being processed",
            "video_id": unique_id
        }), 202

    return jsonify({"error": "Invalid file type"}), 400

def process_video(temp_path, video_id, original_filename):
    try:
        # Generate different resolutions
        resolutions = [
            ('240', '426x240'),
            ('360', '640x360'),
            ('720', '1280x720'),
            ('1080', '1920x1080')
        ]

        for quality, size in resolutions:
            output_path = os.path.join(app.config['UPLOAD_FOLDER'], f"{video_id}_{quality}.mp4")
            (
                ffmpeg
                .input(temp_path)
                .filter('scale', size)
                .output(output_path, crf=23, preset='fast')
                .run(quiet=True)
            )

            # Upload to S3
            s3_key = f"videos/{video_id}/{quality}.mp4"
            s3_client.upload_file(output_path, S3_BUCKET_NAME, s3_key)
            os.remove(output_path)

        # Store metadata
        probe = ffmpeg.probe(temp_path)
        duration = float(probe['format']['duration'])

        videos[video_id] = {
            'id': video_id,
            'title': original_filename,
            'duration': duration,
            'resolutions': [r[0] for r in resolutions],
            'status': 'ready'
        }

        os.remove(temp_path)
    except Exception as e:
        videos[video_id] = {
            'id': video_id,
            'status': 'failed',
            'error': str(e)
        }

@app.route('/videos/<video_id>', methods=['GET'])
@login_required
@rate_limit
def get_video(video_id):
    video = videos.get(video_id)
    if not video:
        return jsonify({"error": "Video not found"}), 404

    if video.get('status') != 'ready':
        return jsonify({"error": "Video not ready"}), 425

    return jsonify(video), 200

def generate_stream(video_id, quality, start=0):
    s3_key = f"videos/{video_id}/{quality}.mp4"
    try:
        obj = s3_client.get_object(Bucket=S3_BUCKET_NAME, Key=s3_key, Range=f"bytes={start}-")
        return obj['Body'].iter_chunks(chunk_size=8192)
    except NoCredentialsError:
        return None

@app.route('/stream/<video_id>/<quality>', methods=['GET'])
@login_required
@rate_limit
def stream_video(video_id, quality):
    video = videos.get(video_id)
    if not video or video.get('status') != 'ready':
        return jsonify({"error": "Video not found or not ready"}), 404

    if quality not in video['resolutions']:
        return jsonify({"error": "Resolution not available"}), 400

    range_header = request.headers.get('Range', '')
    start = 0
    if range_header:
        start = int(range_header.split('=')[1].split('-')[0])

    stream = generate_stream(video_id, quality, start)
    if not stream:
        return jsonify({"error": "Streaming error"}), 500

    response = Response(stream, status=206, mimetype='video/mp4')
    response.headers['Accept-Ranges'] = 'bytes'
    response.headers['Content-Range'] = f'bytes {start}-'
    return response

@app.route('/videos', methods=['GET'])
@login_required
@rate_limit
def list_videos():
    return jsonify(list(videos.values())), 200

@app.route('/progress/<video_id>', methods=['POST'])
@login_required
@rate_limit
def save_progress(video_id):
    data = request.json
    timestamp = data.get('timestamp')
    session_id = request.headers.get('Authorization')
    username = user_sessions.get(session_id)

    if not username:
        return jsonify({"error": "Unauthorized"}), 401

    if not videos.get(video_id):
        return jsonify({"error": "Video not found"}), 404

    video_metadata[video_id][username] = {
        'timestamp': timestamp,
        'updated_at': time.time()
    }

    return jsonify({"message": "Progress saved"}), 200

@app.route('/progress/<video_id>', methods=['GET'])
@login_required
@rate_limit
def get_progress(video_id):
    session_id = request.headers.get('Authorization')
    username = user_sessions.get(session_id)

    if not username:
        return jsonify({"error": "Unauthorized"}), 401

    if not videos.get(video_id):
        return jsonify({"error": "Video not found"}), 404

    progress = video_metadata.get(video_id, {}).get(username, {}).get('timestamp', 0)
    return jsonify({"timestamp": progress}), 200

if __name__ == '__main__':
    if not os.path.exists(UPLOAD_FOLDER):
        os.makedirs(UPLOAD_FOLDER)
    app.run(host='0.0.0.0', port=5000, threaded=True)

