import os
import io
import time
import threading
import queue
import mimetypes
from concurrent.futures import ThreadPoolExecutor
from flask import Flask, request, Response, send_file, jsonify
from werkzeug.utils import secure_filename
from werkzeug.datastructures import FileStorage
from moviepy.editor import VideoFileClip
import ffmpeg

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = 'uploads'
app.config['MAX_CONTENT_LENGTH'] = 50 * 1024 * 1024 * 1024  # 50GB
app.config['ALLOWED_EXTENSIONS'] = {'mp4', 'avi', 'mov', 'mkv', 'flv'}
app.config['TRANSCODED_FOLDER'] = 'transcoded'
app.config['CHUNK_SIZE'] = 1024 * 1024  # 1MB chunks

os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)
os.makedirs(app.config['TRANSCODED_FOLDER'], exist_ok=True)

transcode_queue = queue.Queue()
stream_queues = {}

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in app.config['ALLOWED_EXTENSIONS']

def transcode_worker():
    while True:
        video_id, original_path = transcode_queue.get()
        try:
            resolutions = [
                ('240p', '426x240'),
                ('480p', '854x480'),
                ('720p', '1280x720'),
                ('1080p', '1920x1080')
            ]

            for res_name, res in resolutions:
                output_path = os.path.join(app.config['TRANSCODED_FOLDER'], f"{video_id}_{res_name}.mp4")
                if not os.path.exists(output_path):
                    (
                        ffmpeg
                        .input(original_path)
                        .output(output_path, vf=f'scale={res}', vcodec='libx264', acodec='aac')
                        .run(quiet=True)
                    )
        except Exception as e:
            print(f"Transcoding failed for {video_id}: {str(e)}")
        finally:
            transcode_queue.task_done()

def generate_stream(video_path, start_byte=None, end_byte=None):
    with open(video_path, 'rb') as video_file:
        if start_byte is not None and end_byte is not None:
            video_file.seek(start_byte)
            chunk = video_file.read(end_byte - start_byte + 1)
            yield chunk
        else:
            while True:
                chunk = video_file.read(app.config['CHUNK_SIZE'])
                if not chunk:
                    break
                yield chunk

@app.route('/upload', methods=['POST'])
def upload_video():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400

    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        video_id = str(int(time.time()))
        original_path = os.path.join(app.config['UPLOAD_FOLDER'], f"{video_id}_original.mp4")
        file.save(original_path)

        transcode_queue.put((video_id, original_path))
        return jsonify({'video_id': video_id}), 200

    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/stream/<video_id>', methods=['GET'])
def stream_video(video_id):
    resolution = request.args.get('resolution', '720p')
    video_path = os.path.join(app.config['TRANSCODED_FOLDER'], f"{video_id}_{resolution}.mp4")

    if not os.path.exists(video_path):
        return jsonify({'error': 'Video not available in requested resolution'}), 404

    range_header = request.headers.get('Range', None)
    file_size = os.path.getsize(video_path)

    if range_header:
        start_byte, end_byte = range_header.replace('bytes=', '').split('-')
        start_byte = int(start_byte)
        end_byte = int(end_byte) if end_byte else file_size - 1

        chunk_size = end_byte - start_byte + 1
        headers = {
            'Content-Range': f'bytes {start_byte}-{end_byte}/{file_size}',
            'Accept-Ranges': 'bytes',
            'Content-Length': str(chunk_size),
            'Content-Type': 'video/mp4'
        }

        return Response(
            generate_stream(video_path, start_byte, end_byte),
            status=206,
            headers=headers,
            direct_passthrough=True
        )
    else:
        headers = {
            'Content-Length': str(file_size),
            'Content-Type': 'video/mp4'
        }
        return Response(
            generate_stream(video_path),
            status=200,
            headers=headers,
            direct_passthrough=True
        )

@app.route('/video_info/<video_id>', methods=['GET'])
def get_video_info(video_id):
    resolutions = []
    for res in ['240p', '480p', '720p', '1080p']:
        path = os.path.join(app.config['TRANSCODED_FOLDER'], f"{video_id}_{res}.mp4")
        if os.path.exists(path):
            resolutions.append({
                'resolution': res,
                'size': os.path.getsize(path),
                'duration': VideoFileClip(path).duration
            })

    if not resolutions:
        return jsonify({'error': 'Video not found'}), 404

    return jsonify({
        'video_id': video_id,
        'available_resolutions': resolutions
    })

if __name__ == '__main__':
    for i in range(4):
        threading.Thread(target=transcode_worker, daemon=True).start()

    app.run(host='0.0.0.0', port=5000, threaded=True)
